INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000001', E'주최사에 항의해도 답이 없어요', E'자리 변경 요청드렸는데 무시당했어요. 이런 경우 어디에 문의하나요?', '익명', 'seller', NULL, true, E'익명789', 73, true, NOW() - interval '36 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000001', E'오월엘르 신상 컬렉션 나왔어요!', E'한지 공예 작가입니다. 이번엔 내추럴 스타일로 새 컬렉션 작업했어요. 인스타 들러주세요 :)', '자유게시판', 'seller', E'신예은', false, NULL, 15, true, NOW() - interval '12 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000002', E'플리마켓 첫 참가 후기', E'저는 비즈 팔찌·반지 만드는 차분나무예요. 인스타에서 시작해 오프라인 마켓까지 진출! 첫 마켓 참가했는데 정말 떨렸어요. 그래도 단골손님 한 분 생겨서 행복합니다.', '자유게시판', 'seller', E'한우진', false, NULL, 45, true, NOW() - interval '16 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000003', E'포장재 단가 비교해봤어요', E'디퓨저 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'황연우', false, NULL, 49, true, NOW() - interval '53 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000004', E'주최사에 항의해도 답이 없어요', E'자리 변경 요청드렸는데 무시당했어요. 이런 경우 어디에 문의하나요?', '익명', 'seller', NULL, true, E'익명478', 7, true, NOW() - interval '59 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000006', 'e1000000-0000-0000-0000-000000000004', E'플리마켓 첫 참가 후기', E'저는 천연 향수 만드는 루나소소예요. 풀타임 작가로 전국 마켓 다니며 활동합니다. 첫 마켓 참가했는데 정말 떨렸어요. 그래도 단골손님 한 분 생겨서 행복합니다.', '자유게시판', 'seller', E'신준영', false, NULL, 32, true, NOW() - interval '25 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000007', 'e1000000-0000-0000-0000-000000000005', E'미니미니 신상 컬렉션 나왔어요!', E'유리 공예 컵 작가입니다. 이번엔 코지 스타일로 새 컬렉션 작업했어요. 인스타 들러주세요 :)', '자유게시판', 'seller', E'한도윤', false, NULL, 26, true, NOW() - interval '28 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000008', 'e1000000-0000-0000-0000-000000000005', E'브랜드 네이밍 고민 중이에요', E'지금 미니미니로 활동 중인데 좀 더 컨셉이 명확한 이름으로 바꿀까 고민입니다. 다들 어떻게 정하셨나요?', '자유게시판', 'seller', E'한도윤', false, NULL, 12, true, NOW() - interval '17 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000009', 'e1000000-0000-0000-0000-000000000006', E'캘리그라피 엽서·문구 재료 어디서 구매하시나요?', E'온라인으로만 사다가 오프라인 도매상도 가보고 싶은데 추천 부탁드려요. 서울 기준이면 더 좋아요!', '자유게시판', 'seller', E'문준서', false, NULL, 1, true, NOW() - interval '44 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000010', 'e1000000-0000-0000-0000-000000000006', E'플리마켓 첫 참가 후기', E'저는 캘리그라피 엽서·문구 만드는 아뜰리에오월예요. 본업은 직장인이고 주말마다 셀러로 활동 중이에요. 첫 마켓 참가했는데 정말 떨렸어요. 그래도 단골손님 한 분 생겨서 행복합니다.', '자유게시판', 'seller', E'문준서', false, NULL, 77, true, NOW() - interval '25 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000011', 'e1000000-0000-0000-0000-000000000007', E'카드 단말기 뭐 쓰세요?', E'디자인모카입니다. 토스, 페이코, KIS 비교 중인데 수수료랑 사용감 어떤가요?', '자유게시판', 'seller', E'신지원', false, NULL, 66, true, NOW() - interval '16 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000012', 'e1000000-0000-0000-0000-000000000007', E'디자인모카 신상 컬렉션 나왔어요!', E'가죽 키링·카드지갑 작가입니다. 이번엔 내추럴 스타일로 새 컬렉션 작업했어요. 인스타 들러주세요 :)', '자유게시판', 'seller', E'신지원', false, NULL, 48, true, NOW() - interval '37 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000013', 'e1000000-0000-0000-0000-000000000008', E'핸드드로잉 일러스트 굿즈 셀러분들 디피 어떻게 하세요?', E'코지라일락이라는 작은 브랜드 운영 중이에요. 모던 분위기로 디피하려는데 팁 있으면 공유해주세요!', '자유게시판', 'seller', E'윤윤서', false, NULL, 47, true, NOW() - interval '39 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000014', 'e1000000-0000-0000-0000-000000000008', E'비슷한 품목 옆 부스 스트레스', E'핸드드로잉 일러스트 굿즈 셀러인데 늘 비슷한 카테고리 옆에 배치되네요. 가격 경쟁 너무 힘들어요.', '익명', 'seller', NULL, true, E'익명206', 4, true, NOW() - interval '9 days');
