INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000236', 'e2000000-0000-0000-0000-000000000054', E'꼬치구이 트럭인데 위치 추천 받습니다', E'오리지날마망입니다. 평일 점심 위치 추천해주세요. 직장인 많은 곳 선호!', '자유게시판', 'foodtruck', E'강민준', false, NULL, 51, true, NOW() - interval '54 days');
INSERT INTO public.posts (id, user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('f1000000-0000-0000-0000-000000000237', 'e2000000-0000-0000-0000-000000000055', E'전기/수도 미연결 행사 어떻게 하세요?', E'화덕 피자 트럭이라 전기 필수인데 가끔 미연결 행사 있어요. 자체 발전기 추천 부탁드려요.', '자유게시판', 'foodtruck', E'최지호', false, NULL, 42, true, NOW() - interval '45 days');
